  ('fire-eq-tech-moex-02198', 'fire-eq-tech', 'fire-eq-tech-moex-102-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依爆竹煙火製造儲存販賣場所設置及安全管理辦法規定，有關達管制量摔炮類以外之一般爆竹煙火及舞', '["不得設於潮濕地面", "為地面一層之防 火建築物", "窗戶及出入口應有防盜設施", "儲存場所通路面積應占儲存場所樓地板面積百分之二十五 以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "0a34ee03f2ae", "answer_pdf_sha1": "d13e51cedf0e", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0708", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02199', 'fire-eq-tech', 'fire-eq-tech-moex-102-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法規定，室外儲槽儲存高閃火點物品者，其位 置、構造及設備下列敍述何者錯誤？', '["儲存容量未達管制量一千倍者，周圍保留空地寬度為二公尺以上", "儲存容量未達管制量二千倍者，周圍保留空地寬度為三公尺以上", "儲存容量達管制量二千倍以上者，周圍保留空地寬度為五公尺以上", "幫浦設備周圍保留空地寬度，應在一公尺以上"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "0a34ee03f2ae", "answer_pdf_sha1": "d13e51cedf0e", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0708", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
